  function renderUpdates(){ const diff=local.stagedUpdate?.diff; $('#updates').innerHTML=`<div class="panel"><div class="between"><div><h2>Updates</h2><p class="muted">v120.1 update-flow: Check now/Import JSON → staged diff → lossless gate → apply session → export. Offline Check now opent de JSON-picker.</p></div>${badge(obj('update_manifest').latest_release||'v94.0','green')}</div><div class="row"><button class="btn btn-red" data-action="check-updates">Check now</button><button class="btn" data-action="open-import">Import JSON</button><button class="btn" data-action="import-test-package">Test package</button>${diff?'<button class="btn btn-green" data-action="apply-staged">Apply staged update</button>':''}<button class="btn" data-action="download-update-audit">Export update audit</button></div><div class="update-box" style="margin-top:14px"><b>Status</b><p>${esc(local.lastStatus)}</p>${diff?`<div class="metrics">${metric('target',diff.target)}${metric('nieuw',diff.added.length)}${metric('verdwenen',diff.removed.length,diff.lossless?'lossless OK':'BLOKKER')}${metric('files',diff.changedCounts.length)}</div><div class="table-wrap" style="margin-top:12px"><table class="table"><thead><tr><th>File</th><th>Oud</th><th>Nieuw</th></tr></thead><tbody>${diff.changedCounts.map(x=>`<tr><td>${esc(x.file)}</td><td>${esc(x.old_count)}</td><td>${esc(x.new_count)}</td></tr>`).join('')}</tbody></table></div>`:'<p class="muted">Geen staged update.</p>'}</div></div>`; }
  function renderContent(){ const platforms=[...new Set(arr('items').map(i=>i.platform).filter(Boolean))].sort(); const families=[...new Set(arr('items').map(i=>i.source_family_name||i.source_family_id).filter(Boolean))].sort(); const roles=[...new Set(arr('items').map(i=>i.role).filter(Boolean))].sort(); $('#content').innerHTML=`<div class="panel"><div class="between"><div><h2>Content</h2><p id="contentCount" class="muted"></p></div><button class="btn" data-action="show-all-content">Alles tonen</button></div><div class="filters"><input id="contentSearch" placeholder="Zoek in content"><select id="platformFilter"><option value="">Alle platformen</option>${platforms.map(p=>`<option>${esc(p)}</option>`).join('')}</select><select id="familyFilter"><option value="">Alle families</option>${families.map(f=>`<option>${esc(f)}</option>`).join('')}</select><select id="roleFilter"><option value="">Alle rollen</option>${roles.map(r=>`<option>${esc(r)}</option>`).join('')}</select><select id="sortFilter"><option value="recent">Recent</option><option value="title">Titel A-Z</option><option value="risk">Review-risico eerst</option></select></div><div class="grid" id="contentGrid"></div></div>`; ['contentSearch','platformFilter','familyFilter','roleFilter','sortFilter'].forEach(id=>$('#'+id).addEventListener('input',updateContentGrid)); updateContentGrid(); }
  function filteredItems(){ const q=($('#contentSearch')?.value||$('#globalSearch')?.value||'').toLowerCase().trim(); const p=$('#platformFilter')?.value||''; const f=$('#familyFilter')?.value||''; const r=$('#roleFilter')?.value||''; const s=$('#sortFilter')?.value||'recent'; let out=arr('items').filter(i=>(!q||[i.title,i.description,i.source_name,i.source_family_name,(i.claim_ids||[]).join(' ')].join(' ').toLowerCase().includes(q))&&(!p||i.platform===p)&&(!f||(i.source_family_name===f||i.source_family_id===f))&&(!r||i.role===r)); if(s==='title') out.sort((a,b)=>String(a.title).localeCompare(String(b.title))); else if(s==='risk') out.sort((a,b)=>Number(b.flags?.needs_verification||0)-Number(a.flags?.needs_verification||0)); else out.sort((a,b)=>(b.timeline_at_sort||0)-(a.timeline_at_sort||0)); return out; }
  function updateContentGrid(){ const all=filteredItems(); const shown=all.slice(0,local.limits.content); $('#contentCount').textContent=`${fmt(all.length)} van ${fmt(arr('items').length)} items zichtbaar`; $('#contentGrid').innerHTML=shown.map(i=>`<article class="card content-card" data-item="${esc(i.id)}"><div class="thumb" ${thumbStyle(i)}><img ${imgAttrs(i)} loading="lazy" onerror="window.legolensImageFallback(this)"><div class="thumb-placeholder">Preview niet geladen</div></div><div class="body"><div>${badge(i.platform||'')}${badge(i.role||'')}${(i.claim_ids||[]).length?badge(`${i.claim_ids.length} claims`):''}</div><div class="title">${esc(i.title||i.id)}</div><small class="muted">${esc(i.source_name||i.source_id||'')} • ${esc(i.date_label||i.timeline_at||'')}</small></div></article>`).join('')+(all.length>shown.length?`<div class="mini"><b>${fmt(all.length-shown.length)} meer</b><button class="btn" data-action="show-more-content">Toon meer</button></div>`:''); }
