  function renderIncidents(){ $('#incidents').innerHTML=`<div class="panel"><div class="between"><h2>Incidents & Campaigns</h2>${badge(`${fmt(arr('incidents').length)} incidents`)}</div><div class="grid">${arr('incidents').map(i=>`<div class="card"><div class="body"><div>${badge(i.status||'')}${badge(i.review_status||'')}${badge(`confidence ${Math.round((i.confidence||0)*100)}%`)}</div><h3>${esc(i.title)}</h3><p class="muted">${esc(i.description||'')}</p><div>${badge(`${i.item_count||0} items`)}${badge(`${i.source_count||0} sources`)}</div></div></div>`).join('')}</div></div>`; }
  function renderNetwork(){ const graph=obj('network_graph'); const nodes=(graph.nodes||[]).filter(n=>['incident','family','source','actor','infrastructure'].includes(n.type)).slice(0,110); const ids=new Set(nodes.map(n=>n.id)); const edges=(graph.edges||[]).filter(e=>ids.has(e.source)&&ids.has(e.target)).slice(0,220); const w=980,h=560,cx=w/2,cy=h/2; const placed=nodes.map((n,i)=>{ const r=n.type==='incident'?80:n.type==='actor'?150:n.type==='family'?210:n.type==='infrastructure'?260:300; const a=(i/nodes.length)*Math.PI*2; return {...n,x:cx+Math.cos(a)*r,y:cy+Math.sin(a)*r}; }); const pos=Object.fromEntries(placed.map(n=>[n.id,n])); const col={incident:'#d81f2a',actor:'#f59e0b',family:'#22c55e',infrastructure:'#a855f7',source:'#3b82f6'}; $('#network').innerHTML=`<div class="panel"><div class="between"><div><h2>Network</h2><p class="muted">Incident → actor/family/source → infrastructure graph.</p></div>${badge(`${fmt(graph.summary?.nodes||0)} nodes`)}${badge(`${fmt(graph.summary?.edges||0)} edges`)}</div><div class="graph"><svg viewBox="0 0 ${w} ${h}">${edges.map(e=>`<line class="edge" x1="${pos[e.source].x}" y1="${pos[e.source].y}" x2="${pos[e.target].x}" y2="${pos[e.target].y}"/>`).join('')}${placed.map(n=>`<g class="node"><circle cx="${n.x}" cy="${n.y}" r="${n.type==='incident'?10:n.type==='actor'?9:n.type==='infrastructure'?8:6}" fill="${col[n.type]||'#9ca3af'}"></circle><text x="${n.x+10}" y="${n.y+4}">${esc(String(n.label||n.id).slice(0,32))}</text></g>`).join('')}</svg></div></div>`; }
