  function renderReports(){ const pack=obj('report_pack_v91'); const reports=obj('reports_index').reports||[]; const m=obj('dashboard_metrics_v94_2'); const s=m.series||{}; $('#reports').innerHTML=`<div class="panel"><div class="between"><div><h2>Reports</h2><p class="muted">v120.1 rapportage-dashboard: operationele briefing, evidence appendix, claim matrix, actor/infrastructure dossier en update-integriteit.</p></div><button class="btn" data-action="download-report-pack">Download report pack</button></div><div class="metrics">${metric('report types',(pack.report_types||[]).length)}${metric('report index',reports.length)}${metric('items',counts().items)}${metric('claims',counts().claims)}${metric('candidates',counts().candidates)}${metric('infrastructure',counts().infra)}</div><div class="viz-grid" style="margin-top:14px">${donutChart('Report coverage by type',(pack.report_types||[]).map(x=>({label:x.type||x.report_type||x,value:1})))}<div class="viz-card"><h3>Evidence status for reports</h3>${barRows(s.evidence_status,10)}</div><div class="viz-card"><h3>Reliability risks</h3>${barRows(s.source_reliability,10)}</div><div class="viz-card"><h3>Claim verification matrix</h3>${barRows(s.claim_verification,8)}</div></div><div class="list" style="margin-top:14px">${reports.map(r=>`<div class="line"><span><b>${esc(r.title||r.report_id)}</b><br><small class="muted">${esc(r.path||'')}</small></span>${r.path?`<a class="btn" href="${esc(r.path)}" target="_blank" rel="noopener">Open</a>`:badge(r.format||'report')}</div>`).join('')}</div></div>`; }

  function slugPart(v){ return String(v||'local').toLowerCase().replace(/https?:\/\//,'').replace(/[^a-z0-9]+/g,'_').replace(/^_+|_+$/g,'').slice(0,48)||'local'; }
